use App\Models\Task;use App\Models\TaskActivityLog;use App\Models\User;use App\Support\CurrentWorkspace;
trait Concerns{protected function ws(CurrentWorkspace $cw){return $cw->required();}protected function requirePerm(string $p):void{$u=request()->user();$w=app(\App\Support\CurrentWorkspace::class)->required();$role=$u?->activeWorkspaceMembership($w->id)?->role_key;$map=['workspace_owner'=>['*'],'workspace_admin'=>['*'],'manager'=>['tenant.tasks.create','tenant.tasks.assign','tenant.tasks.update','tenant.tasks.complete','tenant.tasks.approve','tenant.tasks.delete','tenant.daily_reports.review','tenant.daily_reports.approve','tenant.daily_reports.reject','tenant.proofs.review','tenant.proofs.approve','tenant.proofs.reject','tenant.reports.view','tenant.reports.export'],'staff'=>['tenant.tasks.update','tenant.tasks.complete','tenant.daily_reports.submit','tenant.proofs.upload','tenant.reports.view','tenant.reports.export']];$allowed=$u && ((method_exists($u,'can') && $u->can($p)) || in_array('*',$map[$role]??[],true) || in_array($p,$map[$role]??[],true));abort_unless($allowed,403);}protected function workspaceUserIds($workspace){return $workspace->users()->wherePivot('status','active')->pluck('users.id')->all();}protected function logTask(Task $task,string $action,array $old=[],array $new=[],?string $description=null):void{TaskActivityLog::query()->create(['workspace_id'=>$task->workspace_id,'task_id'=>$task->id,'user_id'=>request()->user()?->id,'action'=>$action,'old_values'=>$old?:null,'new_values'=>$new?:null,'description'=>$description]);}}
